<div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre v-pre><code><span class="line">blueprint<span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span><span class="token function">defineLogger</span><span class="token punctuation">(</span>MyCustomLogger<span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">,</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token string-property property">'stone.logger.level'</span><span class="token operator">:</span> <span class="token string">'debug'</span><span class="token punctuation">,</span></span>
