<div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="registering-with-custom-config-1" tabindex="-1"><a class="header-anchor" href="#registering-with-custom-config-1"><span>Registering with custom config</span></a></h4>
